| Fast-path for word-aligned (x&1==0), fully visible 16px bobs on PF2.
| Returns 0 on success (drawn), 1 if needs C fallback.
| ============================================================
        .global DrawBob16Asm
DrawBob16Asm:
        movem.l d2-d7/a2-a6,-(sp)      | 11 regs = 44 bytes
    474a:	movem.l d2-d7/a2-a6,-(sp)

        move.l  48(sp),a2               | a2 = screen_mem
    474e:	movea.l 48(sp),a2
        move.l  52(sp),a3               | a3 = mask ptr
    4752:	movea.l 52(sp),a3
        move.l  56(sp),a4               | a4 = data ptr
    4756:	movea.l 56(sp),a4
        move.w  62(sp),d7               | d7 = x (low 16)
    475a:	move.w 62(sp),d7
        move.w  66(sp),d6               | d6 = y
    475e:	move.w 66(sp),d6
        move.w  70(sp),d5               | d5 = colorMask
    4762:	move.w 70(sp),d5
        move.w  74(sp),d4               | d4 = rows
    4766:	move.w 74(sp),d4

        | --- Fast-path eligibility checks ---
        tst.w   d4
    476a:	tst.w d4
        beq     .db16_fail
    476c:	beq.w 480e <.db16_fail>
        cmpi.w  #-16,d7
    4770:	cmpi.w #-16,d7
        ble     .db16_fail
    4774:	ble.w 480e <.db16_fail>
        cmpi.w  #304,d7
    4778:	cmpi.w #304,d7
        bgt     .db16_fail              | x > 304, right word would be off-screen
    477c:	bgt.w 480e <.db16_fail>
        btst    #0,d7
    4780:	btst #0,d7
        bne     .db16_fail              | not word-aligned
    4784:	bne.w 480e <.db16_fail>
        tst.w   d6
    4788:	tst.w d6
        bmi     .db16_fail              | y < 0, needs clipping
    478a:	bmi.w 480e <.db16_fail>

        | --- Setup ---
        | Plane bases: a0=plane1 (10240), a1=plane3 (30720), a5=plane5 (51200)
        lea     10240(a2),a0
    478e:	lea 10240(a2),a0
        lea     30720(a2),a1
    4792:	lea 30720(a2),a1
        lea     30720(a2),a5
    4796:	lea 30720(a2),a5
        lea     20480(a5),a5
    479a:	lea 20480(a5),a5

        | wx = x >> 4 (word index), byte offset = wx * 2
        move.w  d7,d2
    479e:	move.w d7,d2
