        move.w  d6,d3
    47a4:	move.w d6,d3
        lsl.w   #5,d3                   | d3 = y * 32
    47a6:	lsl.w #5,d3
        move.w  d6,d0
    47a8:	move.w d6,d0
        lsl.w   #3,d0                   | d0 = y * 8
    47aa:	lsl.w #3,d0
        add.w   d0,d3                   | d3 = y * 40
    47ac:	add.w d0,d3
        add.w   d2,d3                   | d3 = y*40 + wx*2 (byte offset)
    47ae:	add.w d2,d3

        | Check row bounds
        move.w  d6,d0
    47b0:	move.w d6,d0
        add.w   d4,d0                   | d0 = y + rows
    47b2:	add.w d4,d0
        cmpi.w  #256,d0
    47b4:	cmpi.w #256,d0
        bgt     .db16_fail              | bottom clip needed
    47b8:	bgt.w 480e <.db16_fail>

